// Get the raw text output from Claude
const rawText = $('Analyze document').first().json.content.parts[0].text;

try {
  // Remove markdown code blocks if Claude adds them anyway
  const cleaned = rawText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // Parse the JSON
  const parsed = JSON.parse(cleaned);

  // Check if document is empty (from prompt's {"empty": true} response)
  if (parsed.empty === true) {
    return [{
      json: {
        success: false,
        error: "empty_document",
        message: "No purchase order data could be extracted from this document."
      }
    }];
  }

  // Format currency symbol
  const currency = parsed.currency || '₱';

  // Format items
  const formatted_items = parsed.items.map((item, index) => {
    const code = item.item_code ? `[${item.item_code}] ` : '';
    const desc = item.description || 'N/A';
    const qty = item.quantity ?? 'N/A';
    const uom = item.uom || '';
    const price = item.unit_price ? `${currency}${item.unit_price}` : 'N/A';
    const total = item.total ? `${currency}${item.total}` : 'N/A';
    return `${index + 1}. ${code}${desc}\n    Qty: ${qty} ${uom} | Price: ${price} | Total: ${total}`;
  }).join('\n\n');

  return [{
    json: {
      success: true,
      data: parsed,
      formatted_items
    }
  }];

} catch (error) {
  return [{
    json: {
      success: false,
      error: "Failed to parse extraction output. The document may be unreadable or unsupported.",
      raw: rawText
    }
  }];
}

